import React, { useState } from 'react';
import AlertsScreen from './app/alerts';
import MapScreen from './app/map';
import utkLogo from './assets/images/utk+logo.png';
import logo from './assets/images/volwash-logo-textless.png';
import ConnectionBanner from './components/ConnectionBanner';
import SensorCard from './components/SensorCard';
import StatsBar from './components/StatsBar';
import { SENSOR_CONFIG } from './constants/sensorConfig';
import { SensorReading, useSensorData } from './hooks/useSensorData';

export default function App() {
  const [activeTab, setActiveTab] = useState<'dash' | 'map' | 'alerts'>('dash');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [selectedDorm, setSelectedDorm] = useState('All');
  const [machineType, setMachineType] = useState<'all' | 'washers' | 'dryers'>('all');
  
  const { sensors, stats, connection } = useSensorData();

  const occupancyRate = stats.total > 0 
    ? Math.round((stats.occupied / stats.total) * 100) 
    : 0;

  const theme = {
    bg: isDarkMode ? '#000000' : '#F2F2F7',
    text: isDarkMode ? '#FFFFFF' : '#000000',
    subtext: isDarkMode ? '#8E8E93' : '#636366',
    nav: isDarkMode ? '#1C1C1E' : '#FFFFFF',
  };

  // Step 1: Filter by Residence Hall
  const dormFiltered = selectedDorm === 'All' 
    ? sensors 
    : sensors.filter((s: SensorReading) => s.location === selectedDorm);

  // Step 2: Filter by Machine Type
  const filteredSensors = dormFiltered.filter((s: SensorReading) => {
    if (machineType === 'washers') return s.id?.toLowerCase().includes('w') || s.name?.toLowerCase().includes('washer');
    if (machineType === 'dryers') return s.id?.toLowerCase().includes('d') || s.name?.toLowerCase().includes('dryer');
    return true;
  });

  const renderDashboard = () => (
    <div style={{ padding: '16px' }}>
      <header style={{ marginBottom: '40px' }}>
        <div style={{ display: 'flex', alignItems: 'center', marginBottom: '32px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
            {/* VolWash Logo HD - No longer a link */}
            <img 
              src={logo} 
              alt="VolWash Logo" 
              style={{ height: '50px', width: 'auto' }}
            />
            
            {/* Unit Identifier */}
            <div>
              <h1 title="VolWash" style={{ 
                fontSize: window.innerWidth > 768 ? '44px' : '38px', 
                margin: 0, 
                fontWeight: 700, 
                color: '#58595B', // Smokey Gray
                lineHeight: 1,
                fontFamily: 'inherit',
                letterSpacing: '-0.02em'
              }}>VolWash</h1>
            </div>
          </div>
        </div>

        {/* Dorm Selector Dropdown */}
        <div>
          <label style={{ display: 'block', fontSize: '12px', fontWeight: 300, color: theme.subtext, textTransform: 'uppercase', marginBottom: '8px' }}>
            Select Residence Hall
          </label>
          <select 
            value={selectedDorm}
            onChange={(e) => setSelectedDorm(e.target.value)}
            style={{
              ...styles.dropdown,
              backgroundColor: isDarkMode ? '#1C1C1E' : '#FFFFFF',
              color: theme.text,
              borderColor: isDarkMode ? '#3A3A3C' : '#D1D1D6'
            }}
          >
            <option value="All">All Dorms</option>
            {SENSOR_CONFIG.LOCATIONS.map(dorm => (
              <option key={dorm} value={dorm}>{dorm}</option>
            ))}
          </select>
        </div>

        {/* Machine Type Filter */}
        <div style={{ marginTop: '16px' }}>
          <label style={{ display: 'block', fontSize: '12px', fontWeight: 300, color: theme.subtext, textTransform: 'uppercase', marginBottom: '8px' }}>
            Filter Machines
          </label>
          <div style={{ display: 'flex', gap: '8px' }}>
            {(['all', 'washers', 'dryers'] as const).map((type) => (
              <button
                key={type}
                onClick={() => setMachineType(type)}
                style={{
                  flex: 1,
                  padding: '10px',
                  borderRadius: '10px',
                  border: '1px solid',
                  fontFamily: 'inherit',
                  fontSize: '14px',
                  cursor: 'pointer',
                  backgroundColor: machineType === type ? SENSOR_CONFIG.COLORS.accent : (isDarkMode ? '#1C1C1E' : '#FFFFFF'),
                  color: machineType === type ? '#FFFFFF' : theme.text,
                  borderColor: isDarkMode ? '#3A3A3C' : '#D1D1D6'
                }}
              >
                {type.charAt(0).toUpperCase() + type.slice(1)}
              </button>
            ))}
          </div>
        </div>
      </header>

      {/* Show the live connection status at the top */}
      {connection && <ConnectionBanner connection={connection} isDarkMode={isDarkMode} />}

      <StatsBar 
        total={stats.total} 
        occupied={stats.occupied} 
        free={stats.free} 
        offline={stats.offline} 
        occupancyRate={occupancyRate} 
        isDarkMode={isDarkMode}
      />

      <div style={styles.grid}>
        {filteredSensors.map((s: SensorReading) => (
          <SensorCard key={s.id} sensor={s} isDarkMode={isDarkMode} />
        ))}
      </div>
    </div>
  );

  const renderContent = () => {
    switch (activeTab) {
      case 'map':    return <MapScreen isDarkMode={isDarkMode} />;
      case 'alerts': return <AlertsScreen isDarkMode={isDarkMode} />;
      default:       return renderDashboard();
    }
  };

  return (
    <div style={{ 
      minHeight: '100vh', 
      backgroundColor: theme.bg, 
      color: theme.text, 
      paddingBottom: '80px', 
      transition: 'background-color 0.3s',
      // Official UTK Brand font prioritized
      fontFamily: 'Gotham, "Montserrat", "Helvetica Neue", Arial, sans-serif'
    }}>
      {/* 1. The Big Orange ID Line (6px UT Orange) */}
      <div style={{ height: '6px', backgroundColor: '#FF8200', width: '100%' }} />

      {renderContent()}

      <nav style={{ 
        ...styles.nav, 
        position: window.innerWidth > 768 ? 'static' : 'fixed',
        margin: window.innerWidth > 768 ? '40px auto' : '0',
        maxWidth: window.innerWidth > 768 ? '600px' : 'none',
        bottom: window.innerWidth > 768 ? 'auto' : '20px',
        left: window.innerWidth > 768 ? 'auto' : '16px',
        right: window.innerWidth > 768 ? 'auto' : '16px',
        backgroundColor: window.innerWidth > 768 ? 'transparent' : '#313e48',
        padding: window.innerWidth > 768 ? '0' : '12px',
        borderRadius: window.innerWidth > 768 ? '0' : '16px',
        boxShadow: window.innerWidth > 768 ? 'none' : '0 8px 32px rgba(0,0,0,0.3)',
      }}>
        <button onClick={() => setActiveTab('dash')} style={{ 
          ...styles.btn, 
          backgroundColor: activeTab === 'dash' ? SENSOR_CONFIG.COLORS.accent : (isDarkMode ? '#1C1C1E' : '#FFFFFF'),
          color: activeTab === 'dash' ? '#FFFFFF' : '#636366',
          border: `1px solid ${isDarkMode ? '#3A3A3C' : '#D1D1D6'}`
        }}>
          <span style={{ fontSize: '12px', fontWeight: 600 }}>Status</span>
        </button>
        <button onClick={() => setActiveTab('map')} style={{ 
          ...styles.btn, 
          backgroundColor: activeTab === 'map' ? SENSOR_CONFIG.COLORS.accent : (isDarkMode ? '#1C1C1E' : '#FFFFFF'),
          color: activeTab === 'map' ? '#FFFFFF' : '#636366',
          border: `1px solid ${isDarkMode ? '#3A3A3C' : '#D1D1D6'}`
        }}>
          <span style={{ fontSize: '12px', fontWeight: 600 }}>Map</span>
        </button>
        <button onClick={() => setActiveTab('alerts')} style={{ 
          ...styles.btn, 
          backgroundColor: activeTab === 'alerts' ? SENSOR_CONFIG.COLORS.accent : (isDarkMode ? '#1C1C1E' : '#FFFFFF'),
          color: activeTab === 'alerts' ? '#FFFFFF' : '#636366',
          border: `1px solid ${isDarkMode ? '#3A3A3C' : '#D1D1D6'}`
        }}>
          <span style={{ fontSize: '12px', fontWeight: 600 }}>Alerts</span>
        </button>
        <button onClick={() => setIsDarkMode(!isDarkMode)} style={{ 
          ...styles.btn, 
          backgroundColor: isDarkMode ? '#1C1C1E' : '#FFFFFF',
          color: '#636366',
          border: `1px solid ${isDarkMode ? '#3A3A3C' : '#D1D1D6'}`
        }}>
          <span style={{ fontSize: '12px', fontWeight: 600 }}>{isDarkMode ? 'Light' : 'Dark'}</span>
        </button>
      </nav>

       {/* Combined UT Footer Section */}
       <div style={{ 
         padding: '48px 16px 140px', 
         backgroundColor: '#313e48',
         color: '#FFFFFF',
         fontSize: '16px',
         borderTop: '6px solid #FF8200' 
       }}>
         <div style={{ ...styles.footerContent, textAlign: 'left' }}>
           <div style={{ marginBottom: '40px' }}>
             <img src={utkLogo} alt="UT Logo" style={{ height: '120px', width: 'auto' }} />
           </div>
 
           <div style={{ marginBottom: '32px', marginLeft: '8px', maxWidth: '800px', lineHeight: '1.8' }}>
             <p style={{ margin: '0 0 16px 0', fontWeight: 300 }}>
               The flagship campus of the <a href="https://tennessee.edu" style={{ color: 'inherit', textDecoration: 'none' }}>University of Tennessee System</a> and partner in the <a href="https://www.tntransferpathway.org" style={{ color: 'inherit', textDecoration: 'none' }}>Tennessee Transfer Pathway</a>.
             </p>
             <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
               <a href="https://www.utk.edu" style={{ color: '#FF8200', textDecoration: 'none', fontWeight: 700, fontSize: '18px' }}>utk.edu</a>
               <a href="https://tickle.utk.edu" style={{ color: '#FF8200', textDecoration: 'none', fontWeight: 700, fontSize: '18px' }}>tickle.utk.edu</a>
             </div>
           </div>
 
           <div style={{ marginBottom: '48px', marginLeft: '8px' }}>
             <p style={{ margin: '0 0 12px 0', fontStyle: 'italic', fontWeight: 700 }}>
               {"Project created by Pon Madan Rangaraj, Aaron Choi, Swagat Khot, and Aarohan Singh".split('').map((char, index) => (
                 <span
                   key={index}
                   style={{
                     display: 'inline-block',
                     whiteSpace: char === ' ' ? 'pre' : 'normal',
                     animation: 'orangeNeonRGB 4s infinite ease-in-out, waveCalm 3s infinite ease-in-out',
                     animationDelay: `${index * 0.05}s`
                   }}
                 >
                   {char}
                 </span>
               ))}
             </p>
             <p style={{ margin: '0 0 32px 0', fontWeight: 700, fontSize: '14px' }}>© 2026 VolWash. All rights reserved.</p>
             
             <div style={{ marginTop: '24px' }}>
               <p style={{ margin: '0 0 4px 0', fontWeight: 700 }}>The University of Tennessee</p>
               <p style={{ margin: '0 0 4px 0', fontWeight: 300 }}>Knoxville, Tennessee 37996</p>
               <p style={{ margin: '0 0 4px 0', fontWeight: 300 }}>865-974-1000</p>
             </div>
           </div>
 
           <div style={{ 
             display: 'flex', 
             flexWrap: 'wrap', 
             gap: '24px', 
             marginLeft: '8px',
             textTransform: 'uppercase',
             fontWeight: 700,
             fontSize: '13px',
             letterSpacing: '0.05em'
           }}>
             <a href="https://dae.utk.edu/eoa/ada/" style={styles.footerLink}>ADA</a>
             <a href="https://www.utk.edu/privacy/" style={styles.footerLink}>Privacy</a>
             <a href="https://safety.utk.edu" style={styles.footerLink}>Safety</a>
             <a href="https://titleix.utk.edu" style={styles.footerLink}>Title IX</a>
           </div>
         </div>
       </div>
 
      <style>
        {`
          @keyframes orangeNeonRGB {
            0%   { color: #FF8200; text-shadow: 0 0 5px rgba(255, 130, 0, 0.4); }
            25%  { color: #FFA500; text-shadow: 0 0 12px rgba(255, 165, 0, 0.7); }
            50%  { color: #FF5E00; text-shadow: 0 0 5px rgba(255, 94, 0, 0.4); }
            75%  { color: #FFB347; text-shadow: 0 0 12px rgba(255, 179, 71, 0.7); }
            100% { color: #FF8200; text-shadow: 0 0 5px rgba(255, 130, 0, 0.4); }
          }
          @keyframes waveCalm {
            0%, 100% { transform: translateY(0); }
            50%      { transform: translateY(-4px); }
          }
        `}
      </style>
    </div>
  );
}

const styles: Record<string, React.CSSProperties> = {
  grid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
    gap: '12px',
    marginTop: '20px'
  },
  nav: {
    position: 'fixed',
    bottom: '20px',
    left: '16px',
    right: '16px',
    height: '70px',
    backgroundColor: 'transparent',
    display: 'flex',
    gap: '8px',
    alignItems: 'center',
    zIndex: 1000
  },
  btn: {
    flex: 1, height: '55px', border: 'none', display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', gap: '4px', cursor: 'pointer', transition: 'all 0.2s', fontFamily: 'inherit', borderRadius: '12px'
  },
  dropdown: {
    width: '100%',
    padding: '12px',
    borderRadius: '12px',
    fontSize: '16px',
    fontWeight: 500,
    border: '1px solid',
    appearance: 'none',
    cursor: 'pointer',
    fontFamily: 'inherit'
  },
  contactBar: {
    marginTop: '40px',
    padding: '32px 16px',
  },
  footerContent: {
    maxWidth: '1200px',
    margin: '0', // Pushed to the left
  },
  footerLink: {
    color: 'inherit',
    textDecoration: 'none',
    fontSize: '11px'
  },
  navIndicator: {
    height: '4px',
    width: '24px',
    backgroundColor: SENSOR_CONFIG.COLORS.accent,
    borderRadius: '4px', // Beveled look
    marginTop: '2px'
  }
};